import base64, os

files = {
    'backend/analyzer.js': '',
    'backend/server.js': '',
    'backend/prisma/schema.prisma': '',
    'frontend/src/App.jsx': '',
}

base = r'C:\Users\Lenovo\OneDrive\Desktop\serper-app'

for rel, b64 in files.items():
    path = os.path.join(base, rel.replace('/', os.sep))
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'wb') as f:
        f.write(base64.b64decode(b64))
    print('Written:', path)

print()
print('All files written!')
print()
print('Now in your serper-app folder run:')
print('  git add backend/analyzer.js backend/server.js backend/prisma/schema.prisma frontend/src/App.jsx')
print('  git commit -m "Add platform fingerprinting, server-side disable list, fix DR disappearing"')
print('  git push origin main')
print()
print('Then SSH into server and run:')
print('  cd /var/www/serper-app && git pull origin main && npm run build --prefix frontend && pm2 restart serper-backend')
